  server: { host: string; port: number };
  database: { url: string; pool_size: number; timeout_ms: number };
  auth: { secret: string; token_ttl: number };
  logging: { level: string; format: string };
}

export function loadConfig(): AppConfig {
  // Read environment variables with fallbacks for required values
  const serverHost = process.env.SERVER_HOST;
  const serverPort = process.env.SERVER_PORT;
  const databaseUrl = process.env.DATABASE_URL;
  const authSecret = process.env.AUTH_SECRET;
  const logLevel = process.env.LOG_LEVEL;

  // Validate required environment variables
  if (!serverHost) {
    throw new Error('SERVER_HOST environment variable is required');
  }
  if (!serverPort) {
    throw new Error('SERVER_PORT environment variable is required');
  }
  if (!databaseUrl) {
    throw new Error('DATABASE_URL environment variable is required');
  }
